// Stripe signature verification
// The raw body and stripe-signature header must be available.
// n8n sends the raw body as $input.first().json.body (string) when responseMode=responseNode
// and the headers in $input.first().json.headers

const webhookSecret = $vars.STRIPE_WEBHOOK_SECRET;
const rawBody = $input.first().json.rawBody || JSON.stringify($input.first().json.body);
const sigHeader = $input.first().json.headers['stripe-signature'];

if (!sigHeader) {
  throw new Error('Missing stripe-signature header');
}

// Parse timestamp and signatures from header
// Format: t=TIMESTAMP,v1=SIG1,v1=SIG2
const parts = sigHeader.split(',');
const tPart = parts.find(p => p.startsWith('t='));
const v1Parts = parts.filter(p => p.startsWith('v1='));

if (!tPart || v1Parts.length === 0) {
  throw new Error('Invalid stripe-signature format');
}

const timestamp = tPart.replace('t=', '');
const signatures = v1Parts.map(p => p.replace('v1=', ''));

// Compute expected signature
// NOTE: This uses the Web Crypto API available in n8n's code node.
// If it is not available, install the stripe npm package via n8n settings
// and use stripe.webhooks.constructEvent() instead.
const signedPayload = timestamp + '.' + rawBody;

// We cannot use Node crypto directly in the sandboxed code node.
// Use the following pattern with n8n's built-in crypto support:
const encoder = new TextEncoder();
const key = await crypto.subtle.importKey(
  'raw',
  encoder.encode(webhookSecret),
  { name: 'HMAC', hash: 'SHA-256' },
  false,
  ['sign']
);
const sigBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
const expectedSig = Array.from(new Uint8Array(sigBuffer))
  .map(b => b.toString(16).padStart(2, '0'))
  .join('');

const valid = signatures.some(sig => sig === expectedSig);

// Tolerance: reject if timestamp is older than 5 minutes
const timeDiff = Math.abs(Date.now() / 1000 - parseInt(timestamp));
if (timeDiff > 300) {
  throw new Error('Stripe webhook timestamp too old: ' + timeDiff + 's');
}

if (!valid) {
  throw new Error('Stripe signature verification failed');
}

const event = typeof $input.first().json.body === 'string'
  ? JSON.parse($input.first().json.body)
  : $input.first().json.body;

return [{ json: { event_type: event.type, event_id: event.id, data: event.data } }];

const session = $('Route Stripe Event').first().json.data.object;

// Extract lead_id from metadata (set when creating the Stripe Checkout session)
const leadId = session.metadata && session.metadata.lead_id;
if (!leadId) {
  throw new Error('checkout.session.completed missing lead_id in metadata. Ensure the Stripe Checkout session is created with metadata.lead_id set.');
}

return [{
  json: {
    lead_id: leadId,
    stripe_customer_id: session.customer,
    stripe_subscription_id: session.subscription,
    customer_email: session.customer_details ? session.customer_details.email : null,
    amount_total: session.amount_total,
    currency: session.currency,
    session_id: session.id
  }
}];
